import { Injectable, signal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Cart } from '../models/storefront.models';

@Injectable({ providedIn: 'root' })
export class CartService {
  private readonly base = `${environment.apiUrl}/cart`;

  /** Item-count for the navbar badge (transient UI state, seeded by the cart view). */
  readonly count = signal<number>(2);

  constructor(private http: HttpClient) {}

  getCart(): Observable<Cart> {
    return this.http.get<Cart>(this.base);
  }

  upsertItem(productId: string, qty: number): Observable<Cart> {
    return this.http.post<Cart>(`${this.base}/items`, { productId, qty });
  }

  updateItem(productId: string, qty: number): Observable<Cart> {
    return this.http.patch<Cart>(`${this.base}/items/${productId}`, { qty });
  }

  removeItem(productId: string): Observable<Cart> {
    return this.http.delete<Cart>(`${this.base}/items/${productId}`);
  }
}
